import React, { useEffect, Suspense } from 'react'
import { Button, DialogOverlay, DialogOverlayActions, DialogOverlayFooter } from '@fs/zion-ui'
import ZionForm, { FormCheckbox, useZionForm } from '@fs/zion-form'
import { trackLink } from '@fs/zion-analytics'
import * as Yup from 'yup'
import { yupResolver } from '@hookform/resolvers/yup'
import { useTranslation } from 'react-i18next'
import { NoticeLoading } from '@fs/zion-icon'

const validationSchema = Yup.object().shape({
  hideMessage: Yup.boolean(),
})

export default function PlaceRequestSubmittedContent({ title, overlay, provisionalPlaceFormValues = {}, onSubmit }) {
  const [t] = useTranslation()
  const methods = useZionForm({
    mode: 'all',
    defaultValues: {
      hideMessage: Boolean(Number(localStorage.getItem('provisional-place-hide-submitted-message'))),
    },
    resolver: yupResolver(validationSchema),
  })

  const { reset } = methods
  const { isOpen, transitioning } = overlay

  const handleSubmit = ({ hideMessage }) => {
    localStorage.setItem('provisional-place-hide-submitted-message', Number(hideMessage))
    onSubmit({ values: provisionalPlaceFormValues })
    overlay.close()
    trackLink({
      to: 'familysearch.org',
      action: 'click_action',
      name: 'ProvisionalPlace:Create New Place:Click',
    })
  }

  useEffect(() => {
    if (!isOpen && !transitioning) {
      reset()
    }
  }, [reset, isOpen, transitioning])

  return (
    <DialogOverlay
      as={ZionForm}
      methods={methods}
      onSubmit={handleSubmit}
      title={title}
      {...overlay}
      closeOnClickAway={false}
    >
      <Suspense fallback={<NoticeLoading />}>
        <p>
          {t(
            'provisional-place.review-place.text',
            "The approval process may take up to 24 hours. In the meantime, we've created a temporary version of the place that you can use now."
          )}
        </p>
        <FormCheckbox
          name="hideMessage"
          label={t('provisional-place.hide-message.text', "Don't show this message again")}
        />
        <DialogOverlayFooter>
          <DialogOverlayActions>
            <Button emphasis="low" type="submit">
              {t('provisional-place.confirm-review.text', 'Got It')}
            </Button>
          </DialogOverlayActions>
        </DialogOverlayFooter>
      </Suspense>
    </DialogOverlay>
  )
}
